# Scratch: "अगर तो" ब्लॉक जैसा ही है
मौसम = input("आज मौसम कैसा है? (धूप/बारिश): ")
if मौसम == "धूप":
    print("बाहर खेलने चलो!")
else:
    print("घर पर प्रोग्रामिंग करो!")

# Scratch: "अगर तो, नहीं तो अगर तो" ब्लॉक जैसा ही है
घंटा = int(input("अभी कितने बजे हैं? (0-23): "))
if घंटा < 10:
    print("सुप्रभात!")
elif घंटा < 17:
    print("नमस्ते!")
else:
    print("शुभ संध्या!")

